SELECT * FROM watch_history
WHERE  user_id = #{userId}
AND  film_id = #{filmId}
LIMIT  1

SELECT * FROM watch_history
WHERE  viewer_hash = #{viewerHash}
AND  film_id     = #{filmId}
LIMIT  1

SELECT * FROM watch_history
WHERE  user_id = #{userId}
ORDER  BY last_watched_at DESC
LIMIT  #{limit}
OFFSET #{offset}
